import { useState } from "react";

export default function AudioExtractor() {
  const [url, setUrl] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const extractAudio = async () => {
    if (!url.trim()) return;

    setLoading(true);
    setError(null);

    try {
      const res = await fetch("http://localhost:5000/extract", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ url }),
      });

      if (!res.ok) {
        throw new Error("Failed to extract audio");
      }

      const blob = await res.blob();

      const downloadUrl = window.URL.createObjectURL(blob);
      const a = document.createElement("a");

      a.href = downloadUrl;
      a.download = "audio.mp3";
      document.body.appendChild(a);
      a.click();

      a.remove();
      window.URL.revokeObjectURL(downloadUrl);
    } catch (err: any) {
      setError(err.message || "Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.backgroundGlow} />
      <div style={styles.card}>
        <div style={styles.badge}>Audio extraction</div>
        <h1 style={styles.title}>Turn any video into a polished MP3</h1>
        <p style={styles.subtitle}>
          Paste a video URL to extract clear audio in seconds. Works with YouTube and other supported links.
        </p>

        <div style={styles.searchBox}>
          <input
            style={styles.input}
            type="text"
            placeholder="Paste video URL here..."
            value={url}
            onChange={(e) => setUrl(e.target.value)}
          />

          <button
            style={styles.button}
            onClick={extractAudio}
            disabled={loading || !url.trim()}
          >
            {loading ? "Extracting..." : "Extract MP3"}
          </button>
        </div>

        <div style={styles.infoRow}>
          <span style={styles.infoPill}>⚡ Fast conversion</span>
          <span style={styles.infoPill}>🎵 High-quality audio</span>
          <span style={styles.infoPill}>🔒 Local download</span>
        </div>

        {error && <div style={styles.errorBox}>{error}</div>}

        {loading && <div style={styles.loadingBox}>Processing your video...</div>}
      </div>
    </div>
  );
}

const styles: Record<string, React.CSSProperties> = {
  container: {
    maxWidth: 600,
    margin: "80px auto",
    textAlign: "center",
    fontFamily: "Arial",
  },
  title: {
    fontSize: 32,
    marginBottom: 10,
  },
  subtitle: {
    color: "#666",
    marginBottom: 30,
  },
  searchBox: {
    display: "flex",
    gap: 10,
  },
  input: {
    flex: 1,
    padding: 12,
    borderRadius: 8,
    border: "1px solid #ccc",
    outline: "none",
  },
  button: {
    padding: "12px 20px",
    borderRadius: 8,
    border: "none",
    backgroundColor: "#111",
    color: "white",
    cursor: "pointer",
  },
  loading: {
    marginTop: 20,
    color: "blue",
  },
  error: {
    marginTop: 20,
    color: "red",
  },
};
